function Leasing(n){var a=this,t=$("#"+n);this.tabID=n,this.calculateInstallment=function(){var n=parseInt(unformatCurrency(t.find("[name='period']").val())),a=parseInt(unformatCurrency(t.find("[name='loanAmount']").val()));a=0==n?0:a/n,t.find("[name='installment']").val(a).blur()},this.rebindEl=function(){},this.loadOnReady=function(){t.find("[name='period'], [name='loanAmount']").change(function(){a.calculateInstallment()}),a.rebindEl()}}